def removeComments(source):
    res = []; s = ''; block = False
    for line in source:
        i = 0
        if not block: s = ''
        while i < len(line):
            if not block and line[i:i+2] == '/*': block = True; i += 1
            elif block and line[i:i+2] == '*/': block = False; i += 1
            elif not block and line[i:i+2] == '//': break
            elif not block: s += line[i]
            i += 1
        if not block and s: res.append(s)
    return res

